#include <stdio.h>
#include <math.h>

long long minNumberOfSeconds(int mountainHeight, int* workerTimes, int workerTimesSize) {
    int sum;
    int a=0;
    int b=1000000;
    for (int i=0; i<workerTimesSize; i++) {
        int t=workerTimes[i];
        if (a<t) {
            a=t;
        }
        if (b>t) {
            b=t;
        }
    }
    int slowest=a;
    int fastest=b;
    int mntByCount = (int)(mountainHeight/workerTimesSize) + 1;
    long secMax=(long)slowest*mntByCount*(1+mntByCount)/2;
    long secMin=fastest;

    long secL=secMin;
    long secR=secMax;
    long secT=(secL+secR)/2;
    printf("limits: L=%d, R=%d\n", secL, secR);

    while (secR-secL>0) {
        printf("limits: L=%d, R=%d\n", secL, secR);
        secT=(secR+secL)/2;
        //printf("finding ans: %d\n", secT);
        sum=0;
        for (int i=0; i<workerTimesSize; i++) {
            int currWorker = workerTimes[i];
            int w = (int)(-0.5 + sqrt(0.25+2*secT/currWorker));
            //printf("worker%d did: %d\n",i , w);
            sum+=w;
        }
        //printf("max work done in %d secs: %d\n", secT, sum);
        if (sum>=mountainHeight) {
            secR=secT;
        } else {
            if (secT==secL) secL++;
            else secL=secT;
        }
    }
    return secR;
}

